mapper.select:
SELECT sr.id, sr.cylinder_id AS cylinderId, c.code AS cylinderCode, sr.user_id AS userId, COALESCE(au.username, su.username) AS username, sr.company_id AS companyId, sr.scan_type AS scanType, sr.scan_time AS scanTime FROM scan_record sr LEFT JOIN cylinder c ON sr.cylinder_id = c.id LEFT JOIN app_user au ON sr.user_id = au.id LEFT JOIN sys_user su ON sr.user_id = su.user_id
sr.company_id = #{companyId}
AND sr.scan_type = #{scanType}
AND c.code LIKE concat('%', #{cylinderCode}, '%')
AND sr.user_id = #{userId}
AND sr.scan_time >= #{startTime}
AND sr.scan_time <= #{endTime}
ORDER BY sr.scan_time DESC
